import{_ as e,c as a,o,a1 as r}from"./chunks/framework.DDNAyvCW.js";const u=JSON.parse('{"title":"Privacy Policy","description":"","frontmatter":{},"headers":[],"relativePath":"docs/privacy/policy/index.md","filePath":"docs/privacy/policy/index.md"}'),n={name:"docs/privacy/policy/index.md"};function i(s,t,c,l,d,p){return o(),a("div",null,t[0]||(t[0]=[r('<h1 id="privacy-policy" tabindex="-1">Privacy Policy <a class="header-anchor" href="#privacy-policy" aria-label="Permalink to &quot;Privacy Policy&quot;">​</a></h1><p>Chaterm collects anonymous usage data to improve the product. Your code, prompts, and conversations are never collected.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Chaterm uses <a href="https://posthog.com" target="_blank" rel="noreferrer">PostHog</a> (an open-source analytics platform) to collect and analyze anonymous usage data. This feedback loop helps the team understand how developers use the product and guides improvements to functionality and user experience.</p><p>Our telemetry implementation is completely transparent -- you can review the <a href="https://github.com/chaterm/Chaterm" target="_blank" rel="noreferrer">source code</a> to see exactly what is tracked.</p><div class="info custom-block"><p class="custom-block-title">Transparency</p><p>All collected data is anonymized before it leaves your device and contains no personally identifiable information (PII). You can audit the telemetry implementation at any time in the public repository.</p></div><h2 id="what-we-track" tabindex="-1">What We Track <a class="header-anchor" href="#what-we-track" aria-label="Permalink to &quot;What We Track&quot;">​</a></h2><p>We collect basic anonymous usage data, including:</p><table tabindex="0"><thead><tr><th>Category</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Task interactions</strong></td><td>Task start and end times, conversation flow (without content)</td></tr><tr><td><strong>Mode and tool usage</strong></td><td>AI modes selected, tools invoked</td></tr><tr><td><strong>Token usage</strong></td><td>Conversation-length metrics for cost estimation (no actual token content)</td></tr><tr><td><strong>UI activity</strong></td><td>Feature usage across the interface</td></tr></tbody></table><h2 id="how-to-opt-out" tabindex="-1">How to Opt Out <a class="header-anchor" href="#how-to-opt-out" aria-label="Permalink to &quot;How to Opt Out&quot;">​</a></h2><p>Telemetry is completely optional:</p><ul><li>When you first install or update Chaterm, a notice about anonymous telemetry is displayed.</li><li>You can change your preference at any time from the privacy settings page.</li></ul><p>For full control over data collection, masking, and sync, see <a href="/docs/privacy/settings/">Privacy Settings</a>.</p>',13)]))}const m=e(n,[["render",i]]);export{u as __pageData,m as default};
